def save_all():
    mem = bytearray(0x10000)
    for addr, data in sorted(dumps.items()):
        for i, b in enumerate(data):
            mem[addr + i] = b

    regions = [
        (0x0000, 0x0100, "zeropage.bin"),
        (0x0600, 0x065C, "irq_handler.bin"),
        (0x06BA, 0x06C9, "sprite_ptr_table.bin"),
        (0x0700, 0x0740, "screen_col_lut.bin"),
        (0x0740, 0x0780, "screen_row_lut.bin"),
        (0x0780, 0x0800, "palette_tables.bin"),
        (0x0800, 0x0880, "physics_table.bin"),
        (0x0880, 0x0C78, "game_engine.bin"),
        (0x0C78, 0x0D00, "music_data1.bin"),
        (0x0D00, 0x0D80, "music_data2.bin"),
        (0x0D80, 0x0E00, "music_data3.bin"),
        (0x0E00, 0x0E80, "encrypted_block.bin"),
        (0x0E80, 0x0F00, "music_data4.bin"),
        (0x0F00, 0x2300, "level_map_full.bin"),
        (0x2800, 0x3700, "level_map_part2.bin"),
        (0x3700, 0x3A00, "tile_graphics_partial.bin"),
        (0x2300, 0x2800, "level_map_gap.bin"),
        (0x3A00, 0x4800, "tile_graphics_rest.bin"),
        (0x4800, 0x5800, "sprite_graphics.bin"),
        (0x7800, 0x8000, "status_bar.bin"),
        # Combined convenience files
        (0x0600, 0x0700, "page6_full.bin"),
        (0x0700, 0x0800, "page7_full.bin"),
        (0x0800, 0x0F00, "engine_tables_music.bin"),
    ]

    for start, end, filename in regions:
        filepath = os.path.join(OUTPUT_DIR, filename)
        with open(filepath, "wb") as f:
            f.write(bytes(mem[start:end]))
        print(f"  {filepath}: ${start:04X}-${end-1:04X} ({end-start} bytes)")

    # Full memory
    filepath = os.path.join(OUTPUT_DIR, "full_memory.bin")
    with open(filepath, "wb") as f:
        f.write(bytes(mem))
    print(f"  {filepath}: full 64KB")

if __name__ == "__main__":
    save_all()
